Petit validateur CLI (simple & utile)
Un script Python très court pour valider un fichier instance contre ce schéma déclaratif (présence des sections et des fields_required internes). Sauvegarde-le en validate_fractal.py :
pythonCopierModifier#!/usr/bin/env python3
import json, sys, pathlib

def load(p):
    return json.loads(pathlib.Path(p).read_text(encoding="utf-8"))

def ensure_dict(d, path, errs):
    if not isinstance(d, dict):
        errs.append(f"{path}: expected object, got {type(d).__name__}")

def validate_instance(schema, inst):
    errs = []

    # 1) sections exigées = toutes les clés de top-level schema
    for section, spec in schema.items():
        if section not in inst:
            errs.append(f"missing section: {section}")
            continue

        sec_inst = inst[section]
        ensure_dict(sec_inst, section, errs)

        # 2) definitions.fields_required
        defs = spec.get("definitions", {})
        req = defs.get("fields_required", [])
        if req:
            if not isinstance(sec_inst, dict):
                errs.append(f"{section}: must be object")
            else:
                for f in req:
                    if f not in sec_inst:
                        errs.append(f"{section}: missing field '{f}'")

        # 3) sous-bloc generation.fields_required (si présent)
        gen = defs.get("generation", {})
        gen_req = gen.get("fields_required", [])
        if gen_req:
            gen_inst = sec_inst.get("generation", {})
            if not isinstance(gen_inst, dict):
                errs.append(f"{section}.generation: missing or not object")
            else:
                for f in gen_req:
                    if f not in gen_inst:
                        errs.append(f"{section}.generation: missing field '{f}'")

    return errs

def main():
    if len(sys.argv) != 3:
        print("Usage: validate_fractal.py SCHEMA.json INSTANCE.json")
        sys.exit(2)
    schema = load(sys.argv[1])
    inst = load(sys.argv[2])
    errs = validate_instance(schema, inst)
    if errs:
        print("❌ INVALID")
        for e in errs:
            print(" -", e)
        sys.exit(1)
    else:
        print("✅ VALID")

if __name__ == "__main__":
    main()

