fractal_normalize.py — ajoute uniquement les clés manquantes d’après ton squelette (celui que tu viens d’envoyer), sans toucher aux valeurs déjà présentes.
pythonCopierModifier#!/usr/bin/env python3
# fractal_normalize.py
import json, sys, pathlib

def load_json(path):
    return json.loads(pathlib.Path(path).read_text(encoding="utf-8"))

def save_json(path, obj):
    pathlib.Path(path).write_text(json.dumps(obj, ensure_ascii=False, indent=2), encoding="utf-8")

def merge_missing(dst, template):
    # Ajoute les clés manquantes de template dans dst (récursif), sans écraser les valeurs existantes
    if isinstance(template, dict):
        if not isinstance(dst, dict):
            return template  # si dst n'est pas dict, on remplace par le squelette
        for k, v in template.items():
            if k not in dst:
                dst[k] = v
            else:
                dst[k] = merge_missing(dst[k], v)
        return dst
    elif isinstance(template, list):
        # si dst est absent ou mauvais type, on prend le type du template (souvent liste vide)
        return dst if isinstance(dst, list) else list(template)
    else:
        # types scalaires: si dst est absent → template, sinon on garde dst
        return dst

def main():
    if len(sys.argv) < 4 or sys.argv[1] not in ("file","dir"):
        print("Usage:")
        print("  python3 fractal_normalize.py file SCHEMA.json TARGET.json")
        print("  python3 fractal_normalize.py dir  SCHEMA.json TARGET_DIR")
        sys.exit(2)

    mode, schema_path, target = sys.argv[1], sys.argv[2], sys.argv[3]
    schema = load_json(schema_path)

    if mode == "file":
        obj = load_json(target)
        obj_norm = merge_missing(obj, schema)
        save_json(target, obj_norm)
        print(f"✅ Normalized: {target}")
    else:
        root = pathlib.Path(target)
        files = list(root.rglob("*.json"))
        for f in files:
            try:
                obj = load_json(f)
            except Exception:
                continue
            obj_norm = merge_missing(obj, schema)
            save_json(f, obj_norm)
        print(f"✅ Normalized {len(files)} JSON files under: {root}")

if __name__ == "__main__":
    main()

