B) Valider la présence des sections/champs clés (niveau “présence”)
fractal_validate.py — vérifie que les clés du squelette existent (peu importe les valeurs). Pratique pour un “OK / KO” rapide.
pythonCopierModifier#!/usr/bin/env python3
# fractal_validate.py
import json, sys, pathlib

def load(p): return json.loads(pathlib.Path(p).read_text(encoding="utf-8"))

def validate_presence(template, obj, path="", errs=None):
    if errs is None: errs = []
    if isinstance(template, dict):
        if not isinstance(obj, dict):
            errs.append(f"{path or '/'}: expected object")
            return errs
        for k, v in template.items():
            if k not in obj:
                errs.append(f"{path}/{k}: missing")
            else:
                validate_presence(v, obj[k], f"{path}/{k}", errs)
    elif isinstance(template, list):
        if not isinstance(obj, list):
            errs.append(f"{path or '/'}: expected list")
    else:
        # scalaires: juste présence de la clé parent (testé plus haut)
        pass
    return errs

def main():
    if len(sys.argv) != 3:
        print("Usage: python3 fractal_validate.py SCHEMA.json INSTANCE.json")
        sys.exit(2)
    schema = load(sys.argv[1])
    inst = load(sys.argv[2])
    errs = validate_presence(schema, inst)
    if errs:
        print("❌ INVALID")
        for e in errs: print(" -", e)
        sys.exit(1)
    print("✅ VALID")

if __name__ == "__main__":
    main()

