fractal_missing.py
pythonCopierModifier#!/usr/bin/env python3
import json, sys, pathlib

def load_json(path):
    return json.loads(pathlib.Path(path).read_text(encoding="utf-8"))

def find_missing(template, obj, path=""):
    missing = []
    if isinstance(template, dict):
        if not isinstance(obj, dict):
            missing.append(path or "/")
            return missing
        for k, v in template.items():
            if k not in obj:
                missing.append((path + "/" + k).lstrip("/"))
            else:
                missing.extend(find_missing(v, obj[k], f"{path}/{k}"))
    elif isinstance(template, list):
        if not isinstance(obj, list):
            missing.append(path or "/")
    return missing

def check_file(schema, file):
    try:
        obj = load_json(file)
    except Exception as e:
        return [f"{file}: parse error {e}"]
    return find_missing(schema, obj)

def main():
    if len(sys.argv) < 3:
        print("Usage:")
        print("  python3 fractal_missing.py SCHEMA.json file.json")
        print("  python3 fractal_missing.py SCHEMA.json DIRECTORY/")
        sys.exit(2)

    schema = load_json(sys.argv[1])
    target = pathlib.Path(sys.argv[2])

    if target.is_file():
        missing = check_file(schema, target)
        if missing:
            print(f"❌ {target}: missing ->")
            for m in missing: print(" -", m)
        else:
            print(f"✅ {target}: all keys present")
    else:
        files = list(target.rglob("*.json"))
        for f in files:
            missing = check_file(schema, f)
            if missing:
                print(f"❌ {f.relative_to(target)}")
                for m in missing: print("   -", m)

if __name__ == "__main__":
    main()


