    fields = ["level","file","ident","issue","detail","relation","relationType","cardinality","target"]
    with p.open("w", encoding="utf-8", newline="") as f:
        w = csv.DictWriter(f, fieldnames=fields)
        w.writeheader()
        for r in rows:
            w.writerow({k: r.get(k,"") for k in fields})

def _as_items_list(data, keys=("relations","relationTypes","items","types")):
    if isinstance(data, list):
        return data
    if isinstance(data, dict):
        for k in keys:
            v = data.get(k)
            if isinstance(v, list):
                return v
    return []

def load_relation_types(rel_type_path: pathlib.Path):
    data = load_json(rel_type_path)
    items = _as_items_list(data, keys=("relationTypes","types","items","relations"))
    return {x["ident"]: x for x in items if isinstance(x, dict) and x.get("ident")}

def load_relations(relations_path: pathlib.Path):
    data = load_json(relations_path)
    items = _as_items_list(data, keys=("relations","items","types","relationTypes"))
    return {x["ident"]: x for x in items if isinstance(x, dict) and x.get("ident")}

def get(obj, path):
    cur = obj
    for part in path.split("/"):
        if isinstance(cur, dict) and part in cur:
            cur = cur[part]
        else:
            return None
    return cur

def main():
    if len(sys.argv) < 4:
        print("Usage: python3 fractal_relations_validate.py VALIDATED_DIR relations.json relationType.json")
        sys.exit(2)

    validated_dir = pathlib.Path(sys.argv[1]).resolve()
    relations_path = pathlib.Path(sys.argv[2]).resolve()
    rel_type_path  = pathlib.Path(sys.argv[3]).resolve()

    if not validated_dir.is_dir():
        print("Target dir not found:", validated_dir); sys.exit(2)
    if not relations_path.exists():
        print("relations.json not found:", relations_path); sys.exit(2)
    if not rel_type_path.exists():
        print("relationType.json not found:", rel_type_path); sys.exit(2)

    rel_types = load_relation_types(rel_type_path)
    rels = load_relations(relations_path)

    issues = []
    report = {
        "summary": {
            "unknown_relationType": 0,
            "unknown_relation_ident": 0,
            "instance_cardinality_mismatch": 0,
            "instance_target_invalid": 0,
            "files_checked": 0
        },
        "files":[]
    }

    for r_ident, r in rels.items():
        rt = r.get("relationType")
        if rt and rt not in rel_types:
            issues.append({
                "level": "error",
                "file": str(relations_path),
                "ident": r_ident,
                "issue": "unknown_relationType_in_relations_catalog",
                "detail": f"relationType '{rt}' non défini dans relationType.json",
                "relation": r_ident,
                "relationType": rt
            })
            report["summary"]["unknown_relationType"] += 1

    files = [p for p in validated_dir.glob("*.json")]
    for p in files:
        try:
            obj = load_json(p)
        except Exception as e:
            issues.append({
                "level":"error","file":str(p),"ident":"(parse)",
                "issue":"parse_error","detail":str(e)
            })
            continue

        report["summary"]["files_checked"] += 1
        ident = get(obj, "identity/ident") or p.stem
        instances = get(obj, "context/relations")
        if instances is None:
            report["files"].append({"file":str(p),"ident":ident,"instances":0})
            continue

        if isinstance(instances, dict):
            issues.append({
                "level":"warning","file":str(p),"ident":ident,
                "issue":"relations_not_list","detail":"context.relations devrait être une liste d'instances"
            })
            inst_list = []
        elif isinstance(instances, list):
            inst_list = instances
        else:
            issues.append({
                "level":"warning","file":str(p),"ident":ident,
                "issue":"relations_invalid_type","detail":f"type {type(instances).__name__}"
            })
            inst_list = []

        for inst in inst_list:
            rel_ident = inst.get("relation")
            rt = rels.get(rel_ident, {}).get("relationType") if rel_ident in rels else None
            inst_card = inst.get("cardinality")
            cat_card  = rels.get(rel_ident, {}).get("cardinality") if rel_ident in rels else None
            tgt = inst.get("target")

            if not isinstance(rel_ident, str) or not rel_ident:
                issues.append({
                    "level":"error","file":str(p),"ident":ident,
                    "issue":"instance_missing_relation","detail":"relation manquante ou vide"
                })
                report["summary"]["unknown_relation_ident"] += 1
                continue

            if rel_ident not in rels:
                issues.append({
                    "level":"error","file":str(p),"ident":ident,
                    "relation":rel_ident,
                    "issue":"unknown_relation_ident","detail":"relation non listée dans relations.json"
                })
                report["summary"]["unknown_relation_ident"] += 1

            if rel_ident in rels and rt and rt not in rel_types:
                issues.append({
                    "level":"error","file":str(p),"ident":ident,
                    "relation":rel_ident,"relationType":rt,
                    "issue":"unknown_relationType_for_relation","detail":"relationType non présent dans relationType.json"
                })
                report["summary"]["unknown_relationType"] += 1

            if isinstance(inst_card, str) and isinstance(cat_card, str) and inst_card != cat_card:
                issues.append({
                    "level":"warning","file":str(p),"ident":ident,
                    "relation":rel_ident,"cardinality":inst_card,
                    "issue":"instance_cardinality_mismatch","detail":f"catalogue={cat_card}, instance={inst_card}"
                })
                report["summary"]["instance_cardinality_mismatch"] += 1

            if not isinstance(tgt, str) or not tgt:
                issues.append({
                    "level":"warning","file":str(p),"ident":ident,
                    "relation":rel_ident,"issue":"instance_target_invalid","detail":"target vide ou non-string"
                })
                report["summary"]["instance_target_invalid"] += 1

        report["files"].append({"file":str(p),"ident":ident,"instances":len(inst_list)})

    out_json = validated_dir / "relations_validation_report.json"
    out_csv  = validated_dir / "relations_validation_issues.csv"
    write_json(out_json, {"report":report, "issues":issues})
    write_csv(out_csv, issues)

    has_errors = any(i.get("level") == "error" for i in issues)
    print(f"📄 JSON : {out_json}")
    print(f"📄 CSV  : {out_csv}")
    print(f"Résumé : {report['summary']}")
    sys.exit(1 if has_errors else 0)

if __name__ == "__main__":
    main()
