#!/usr/bin/env python3
# description : Migration relations → format normalisé (liste d'instances) + ajout <objecttype>type (+tag). Gère alias scoppés (ex. tag_of→related_to scope=tag).
# howto :
#   # Dry-run :
#   python3 fractal_relations_migrate.py <VALIDATED_DIR> relations.json --dry-run
#   # Appliquer :
#   python3 fractal_relations_migrate.py <VALIDATED_DIR> relations.json --write-dot

import json, sys, pathlib, re
from copy import deepcopy

def load_json(p): return json.loads(pathlib.Path(p).read_text(encoding="utf-8"))
def save_json(p, o): pathlib.Path(p).write_text(json.dumps(o, ensure_ascii=False, indent=2), encoding="utf-8")

def infer_object_type_from_filename(path: pathlib.Path):
    m = re.match(r"meta([a-z0-9]+)_catalog\.json$", path.name)
    return m.group(1) if m else None

def ensure_object_type_field_and_tag(obj, object_type):
    if not object_type: return False, None
    key = f"{object_type}type"
    ident = obj.setdefault("identity", {})
    before = key in ident
    ident.setdefault(key, "")
    val = ident.get(key, "")
    tags = ident.setdefault("tags", [])
    if isinstance(val, str) and val:
        tagval = f"{object_type}:{val}"
        if tagval not in tags: tags.append(tagval)
    return (not before), key

def normalize_old_relations_to_list(rel_block):
    if isinstance(rel_block, list):
        return deepcopy(rel_block)
    if not isinstance(rel_block, dict):
        return []
    out = []
    def add_many(r, vals):
        for v in (vals if isinstance(vals, list) else []):
            if isinstance(v, str) and v: out.append({"relation": r, "target": v})
    def add_one(r, v):
        if isinstance(v, str) and v: out.append({"relation": r, "target": v})
    add_many("depends_on",           rel_block.get("depends_on"))
    add_many("related_to",           rel_block.get("related_to"))
    add_many("applies_to_objects",   rel_block.get("applies_to_objects"))
    add_many("consumes",             rel_block.get("consumes"))
    add_many("produces",             rel_block.get("produces"))
    add_one("inherits_from",         rel_block.get("inherits_from"))
    add_one("alias_of",              rel_block.get("alias_of"))
    # alias scoppé
    if isinstance(rel_block.get("tag_of"), list):
        for v in rel_block["tag_of"]:
            if isinstance(v, str) and v:
                out.append({"relation": "related_to", "target": v, "scope": "tag"})
    return out

def load_relation_catalog(relations_path: pathlib.Path):
    data = load_json(relations_path)
    items = data.get("relations") or data.get("items") or (data if isinstance(data, list) else [])
    return {it.get("ident"): it for it in items if isinstance(it, dict) and it.get("ident")}

def validate_and_keep(instances, known_rel):
    out, issues = [], []
    for inst in instances:
        r, t = inst.get("relation"), inst.get("target")
        if not isinstance(r, str) or not r:
            issues.append({"issue":"missing_relation", "inst":inst}); continue
        if r not in known_rel:
            issues.append({"issue":"unknown_relation", "relation":r, "inst":inst})
        if not isinstance(t, str) or not t:
            issues.append({"issue":"missing_target", "relation":r, "inst":inst}); continue
        out.append(inst)
    return out, issues

def write_dot(path, edges):
    with path.open("w", encoding="utf-8") as f:
        f.write("digraph relations {\n  rankdir=LR;\n  node [shape=box];\n")
        for s, r, t in edges:
            f.write(f'  "{s}" -> "{t}" [label="{r}"];\n')
        f.write("}\n")

def main():
    if len(sys.argv) < 3:
        print("Usage: python3 fractal_relations_migrate.py VALIDATED_DIR relations.json [--dry-run] [--write-dot]")
        sys.exit(2)
    root = pathlib.Path(sys.argv[1]).resolve()
    relations_path = pathlib.Path(sys.argv[2]).resolve()
    dry_run = ("--dry-run" in sys.argv)
    write_graph = ("--write-dot" in sys.argv)
    if not root.is_dir(): print("Target dir not found:", root); sys.exit(2)
    if not relations_path.exists(): print("relations.json not found:", relations_path); sys.exit(2)

    known_rel = load_relation_catalog(relations_path)
    report, edges = {"files": [], "summary": {"modified":0,"issues":0}}, []
    files = [p for p in root.glob("*.json")]

    for p in files:
        try: obj = load_json(p)
        except Exception as e:
            report["files"].append({"file":str(p), "error":f"parse_error: {e}"}); report["summary"]["issues"] += 1; continue

        object_type = infer_object_type_from_filename(p)
        created_type_field, type_key = ensure_object_type_field_and_tag(obj, object_type)

        ctx = obj.setdefault("context", {})
        # si déjà une liste d'instances, on ne touche pas
        current = ctx.get("relations")
        if isinstance(current, list):
            inst = current
        else:
            # sinon, tenter de convertir un ancien dict éventuel
            inst = normalize_old_relations_to_list(current if isinstance(current, dict) else {})

        inst2, issues = validate_and_keep(inst, known_rel)
        report["summary"]["issues"] += len(issues)
        ctx["relations"] = inst2  # impose le format liste (peut être vide)

        src_ident = obj.get("identity", {}).get("ident") or p.stem
        for i in inst2:
            edges.append((src_ident, i.get("relation","?"), i.get("target","?")))

        if not dry_run:
            save_json(p, obj)

        report["files"].append({
            "file": str(p),
            "object_type": object_type,
            "added_type_field": created_type_field,
            "type_key": type_key or "",
            "relations_instances": len(inst2),
            "issues": issues
        })
        report["summary"]["modified"] += 1

    out_json = root / "relations_migration_report.json"
    out_dot  = root / "relations_graph.dot"
    out_json.write_text(json.dumps(report, ensure_ascii=False, indent=2), encoding="utf-8")
    if write_graph:
        write_dot(out_dot, edges)
    print(f"📄 Report : {out_json}")
    if write_graph: print(f"🗺️  DOT   : {out_dot}")
    print(f"Résumé : {report['summary']}")
if __name__ == "__main__":
    main()
