A) Générer un plan de relations (suggestions)
Scanne les JSON validés, repère les ident des autres objets mentionnés (dans identity, view, context, etc.) et propose des related_to (ou ce que tu veux) dans un fichier relations_plan.json que tu peux éditer.
bashCopierModifiercat > temp/methods/fractal/fractal_relations_plan_suggest.py <<'EOF'
#!/usr/bin/env python3
# description : Génère un plan de relations (suggestions) en détectant les ident d'autres objets mentionnés dans chaque fichier.
# howto :
#   python3 temp/methods/fractal/fractal_relations_plan_suggest.py temp/all/fractal/VALIDATED relations.json > temp/all/fractal/VALIDATED/relations_plan.json

import json, sys, pathlib, re
from collections import defaultdict

def load_json(p): return json.loads(pathlib.Path(p).read_text(encoding="utf-8"))

def walk(obj):
    if isinstance(obj, dict):
        for v in obj.values(): yield from walk(v)
    elif isinstance(obj, list):
        for v in obj: yield from walk(v)
    else:
        yield obj

def main():
    if len(sys.argv) < 3:
        print("Usage: python3 fractal_relations_plan_suggest.py VALIDATED_DIR relations.json", file=sys.stderr); sys.exit(2)
    root = pathlib.Path(sys.argv[1]).resolve()
    relcat = load_json(sys.argv[2])
    rel_items = relcat.get("relations") or relcat.get("items") or (relcat if isinstance(relcat, list) else [])
    known_rel = {r.get("ident") for r in rel_items if isinstance(r, dict)}

    # heuristique pour reconnaître des ident d'objets: metaXXX_catalog.json -> identity.ident si présent, sinon basename sans extension
    files = list(root.glob("*.json"))
    idents = {}
    for p in files:
        try:
            o = load_json(p)
        except: 
            continue
        ident = (o.get("identity", {}) or {}).get("ident") or p.stem
        idents[ident] = p.name

    # regex simple pour capter un ident connu dans des strings
    pattern = re.compile(r"\b(" + "|".join(map(re.escape, sorted(idents))) + r")\b") if idents else None

    plan = {"relations": []}  # [{file, from_ident, instances:[{relation,target,scope?,cardinality?}]}]
    for p in files:
        try:
            o = load_json(p)
        except:
            continue
        src_ident = (o.get("identity", {}) or {}).get("ident") or p.stem

        mentions = set()
        for val in walk(o):
            if isinstance(val, str) and pattern:
                for m in pattern.findall(val):
                    if m and m != src_ident:
                        mentions.add(m)

        # suggestion par défaut : related_to
        instances = [{"relation": "related_to", "target": m} for m in sorted(mentions)]
        if instances:
            plan["relations"].append({
                "file": p.name,
                "from_ident": src_ident,
                "instances": instances
            })

    print(json.dumps(plan, ensure_ascii=False, indent=2))
if __name__ == "__main__":
    main()
EOF
