B) Appliquer le plan (idempotent + validation)
Ce script lit relations_plan.json, insère ces relations dans chaque fichier (en évitant les doublons), puis relance une vérification simple.
bashCopierModifiercat > temp/methods/fractal/fractal_relations_plan_apply.py <<'EOF'
#!/usr/bin/env python3
# description : Applique un plan de relations (relations_plan.json) aux fichiers VALIDATED, de manière idempotente.
# howto :
#   python3 temp/methods/fractal/fractal_relations_plan_apply.py temp/all/fractal/VALIDATED temp/all/fractal/VALIDATED/relations_plan.json relations.json

import json, sys, pathlib

def load_json(p): return json.loads(pathlib.Path(p).read_text(encoding="utf-8"))
def save_json(p, o): pathlib.Path(p).write_text(json.dumps(o, ensure_ascii=False, indent=2), encoding="utf-8")

def _as_relcat_map(data):
    items = data.get("relations") or data.get("items") or (data if isinstance(data, list) else [])
    return {x.get("ident"): x for x in items if isinstance(x, dict) and x.get("ident")}

def main():
    if len(sys.argv) < 4:
        print("Usage: python3 fractal_relations_plan_apply.py VALIDATED_DIR relations_plan.json relations.json")
        sys.exit(2)
    root = pathlib.Path(sys.argv[1]).resolve()
    plan_path = pathlib.Path(sys.argv[2]).resolve()
    rels_path = pathlib.Path(sys.argv[3]).resolve()

    plan = load_json(plan_path)
    relcat = _as_relcat_map(load_json(rels_path))
    ok_rel = set(relcat.keys())

    plan_items = plan.get("relations", [])
    count_add, files_touched = 0, 0
    issues = []

    # index fichiers
    files = {p.name: p for p in root.glob("*.json")}

    for entry in plan_items:
        fname = entry.get("file")
        insts = entry.get("instances") or []
        if fname not in files:
            issues.append({"file": fname, "issue": "file_not_found"}); continue
        p = files[fname]
        try:
            o = load_json(p)
        except Exception as e:
            issues.append({"file": fname, "issue": f"parse_error: {e}"}); continue

        ctx = o.setdefault("context", {})
        rel_list = ctx.setdefault("relations", [])
        # idempotence: on indexe existants (relation,target,scope,cardinality)
        def sig(x): 
            return (x.get("relation"), x.get("target"), x.get("scope"), x.get("cardinality"))
        existing = {sig(x) for x in rel_list if isinstance(x, dict)}

        added_here = 0
        for r in insts:
            if not isinstance(r, dict):
                continue
            rel = r.get("relation"); tgt = r.get("target")
            if not isinstance(rel, str) or not rel or rel not in ok_rel:
                issues.append({"file": fname, "issue":"unknown_relation", "relation": rel}); continue
            if not isinstance(tgt, str) or not tgt:
                issues.append({"file": fname, "issue":"invalid_target", "relation": rel}); continue
            s = sig(r)
            if s in existing:
                continue
            rel_list.append(r)
            existing.add(s)
            added_here += 1
            count_add += 1

        if added_here:
            save_json(p, o)
            files_touched += 1

    out = {
        "summary": {"files_touched": files_touched, "relations_added": count_add, "issues": len(issues)},
        "issues": issues
    }
    (root / "relations_plan_apply_report.json").write_text(json.dumps(out, ensure_ascii=False, indent=2), encoding="utf-8")
    print(json.dumps(out, ensure_ascii=False, indent=2))

if __name__ == "__main__":
    main()
EOF
