temp/methods/fractal/fractal_object_types_scan.py
pythonCopierModifier#!/usr/bin/env python3
# description : Scanne un répertoire de catalogues et dresse la liste des object types (meta<type>_catalog.json), avec comptages et sous-types détectés.
# howto :
#   python3 temp/methods/fractal/fractal_object_types_scan.py temp/all/fractal/VALIDATED
#   # (optionnel) changer de dossier de sortie
#   python3 temp/methods/fractal/fractal_object_types_scan.py temp/all/fractal/VALIDATED --out temp/all/fractal/VALIDATED

import sys, json, pathlib, re, csv
from collections import Counter, defaultdict

def load_json(p: pathlib.Path):
    return json.loads(p.read_text(encoding="utf-8"))

def infer_objecttype_from_filename(name: str):
    m = re.match(r"meta([a-z0-9]+)_catalog\.json$", name)
    return m.group(1) if m else None

def detect_subtypes(obj: dict):
    """
    Récupère tous les champs *type (ex: methodtype, objecttype…) + tags 'type:*'
    Retourne: { "fields": {"methodtype": "xyz", ...}, "tags": ["method:foo", ...] }
    """
    sub_fields = {}
    ident = obj.get("identity", {}) if isinstance(obj, dict) else {}
    # clés finissant par 'type'
    for k, v in ident.items():
        if isinstance(k, str) and k.endswith("type") and isinstance(v, str) and v.strip():
            sub_fields[k] = v.strip()
    # tags
    tags = []
    tag_list = ident.get("tags", [])
    if isinstance(tag_list, list):
        for t in tag_list:
            if isinstance(t, str) and ":" in t:
                tags.append(t)
    return {"fields": sub_fields, "tags": tags}

def main():
    if len(sys.argv) < 2:
        print("Usage: python3 fractal_object_types_scan.py <DIR> [--out <OUTDIR>]")
        sys.exit(2)

    root = pathlib.Path(sys.argv[1]).resolve()
    if not root.is_dir():
        print("Target dir not found:", root)
        sys.exit(2)

    outdir = root
    if "--out" in sys.argv:
        try:
            outdir = pathlib.Path(sys.argv[sys.argv.index("--out")+1]).resolve()
            outdir.mkdir(parents=True, exist_ok=True)
        except Exception:
            pass

    files = sorted(p for p in root.glob("*.json"))
    rows = []
    type_counter = Counter()
    subtypes_by_type = defaultdict(lambda: Counter())

    for p in files:
        try:
            o = load_json(p)
        except Exception as e:
            rows.append({
                "file": p.name, "ident": "", "objecttype": "", 
                "subtype_fields": "", "subtype_tags": "", "error": f"parse_error: {e}"
            })
            continue

        ident = (o.get("identity", {}) or {}).get("ident") or p.stem
        ot = infer_objecttype_from_filename(p.name) or ""
        det = detect_subtypes(o)
        subtype_fields = det["fields"]  # dict
        subtype_tags = det["tags"]      # list

        if ot:
            type_counter[ot] += 1
            # tenter de résumer un "sous-type principal" si une clé matche <objecttype>type
            main_key = f"{ot}type"
            if main_key in subtype_fields:
                subtypes_by_type[ot][subtype_fields[main_key]] += 1

        rows.append({
            "file": p.name,
            "ident": ident,
            "objecttype": ot,
            "subtype_fields": ";".join([f"{k}={v}" for k,v in subtype_fields.items()]) if subtype_fields else "",
            "subtype_tags": ";".join(subtype_tags) if subtype_tags else "",
            "error": ""
        })

    summary = {
        "object_types": [{"type": t, "count": c} for t, c in sorted(type_counter.items(), key=lambda x:(-x[1], x[0]))],
        "subtypes": {
            t: [{"value": v, "count": c} for v, c in sorted(cnt.items(), key=lambda x:(-x[1], x[0]))]
            for t, cnt in subtypes_by_type.items()
        },
        "files_scanned": len(files)
    }

    # Écritures
    out_json = outdir / "object_types_summary.json"
    out_csv  = outdir / "object_types_files.csv"
    out_json.write_text(json.dumps(summary, ensure_ascii=False, indent=2), encoding="utf-8")

    with out_csv.open("w", encoding="utf-8", newline="") as f:
        w = csv.DictWriter(f, fieldnames=["file","ident","objecttype","subtype_fields","subtype_tags","error"])
        w.writeheader()
        for r in rows:
            w.writerow(r)

    # Affichage court
    print("=== Object types ===")
    for t,c in sorted(type_counter.items(), key=lambda x:(-x[1], x[0])):
        print(f"- {t}: {c}")
    if subtypes_by_type:
        print("\n=== Subtypes (by type) ===")
        for t, cnt in sorted(subtypes_by_type.items()):
            top = ", ".join([f"{v}({n})" for v,n in cnt.most_common(10)])
            print(f"- {t}: {top}")

    print(f"\n📄 JSON : {out_json}")
    print(f"📄 CSV  : {out_csv}")

if __name__ == "__main__":
    main()


